60	 * Recursively introspect a type id, exercising the target APIs.
61	 * depth prevents unbounded recursion on pathological compound-of-compound
62	 * types in a fuzzed file.
63	 */
64	static void introspect_type(hid_t tid, int depth)
65	{
66	    if (tid < 0 || depth > 8)
67	        return;
68	
69	    H5T_class_t cls = H5Tget_class(tid);
70	    H5Tget_size(tid);
71	    H5Tis_variable_str(tid);
72	
73	    if (cls == H5T_COMPOUND) {
74	        int nmembers = H5Tget_nmembers(tid);
75	        if (nmembers > 0) {
76	            /* Cap iterations to avoid spending too much time on huge types. */
77	            int limit = nmembers < 64 ? nmembers : 64;
78	            for (int i = 0; i < limit; i++) {
79	                H5Tget_member_offset(tid, (unsigned)i);
80	                hid_t mtype = H5Tget_member_type(tid, (unsigned)i);
81	                if (mtype >= 0) {
82	                    introspect_type(mtype, depth + 1);
83	                    H5Tclose(mtype);
84	                }
85	            }
86	        }
87	    } else if (cls == H5T_ENUM) {
88	        int nmembers = H5Tget_nmembers(tid);
89	        if (nmembers > 0) {
90	            int limit = nmembers < 64 ? nmembers : 64;
91	            for (int i = 0; i < limit; i++) {
92	                H5Tget_member_offset(tid, (unsigned)i);
93	            }
94	        }
95	    } else if (cls == H5T_ARRAY || cls == H5T_VLEN) {
96	        hid_t base = H5Tget_super(tid);
97	        if (base >= 0) {
98	            introspect_type(base, depth + 1);
99	            H5Tclose(base);
100	        }
101	    }
102	}
