120	        H5Pclose(fapl);
121	        return 0;
122	    }
123	
124	    if (H5Pset_file_image(fapl, (void *)data, size) < 0) {
125	        H5Pclose(fapl);
126	        return 0;
127	    }
128	
129	    /* Open the in-memory image as an HDF5 file (read-only). */
130	    hid_t fid = H5Fopen("fuzz_image", H5F_ACC_RDONLY, fapl);
131	    H5Pclose(fapl);
132	    if (fid < 0)
133	        return 0;
