136	    for (int i = 0; i < NUM_CANDIDATES; i++) {
137	        hid_t tid = H5Topen2(fid, CANDIDATE_NAMES[i], H5P_DEFAULT);
138	        if (tid >= 0) {
139	            introspect_type(tid, 0);
140	            H5Tclose(tid);
141	        }
142	    }
143	
144	    /* Also walk the root group to find whatever names are actually present
145	     * and try to open them as committed types.                              */
146	    hsize_t idx = 0;
147	    hid_t root = H5Gopen2(fid, "/", H5P_DEFAULT);
148	    if (root >= 0) {
149	        hsize_t n = 0;
150	        H5Gget_num_objs(root, &n);
151	        /* Cap at 32 to bound work on pathological files. */
152	        hsize_t limit = n < 32 ? n : 32;
153	        for (hsize_t j = 0; j < limit; j++) {
154	            char name[256];
155	            ssize_t name_len = H5Gget_objname_by_idx(root, j, name, sizeof(name));
